s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')


class DecimalEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, Decimal):
            return float(obj)
        return super(DecimalEncoder, self).default(obj)


def lambda_handler(event, context):
    try:
        function_name = context.function_name
        request_id = context.request_id
        
        table_name = os.environ.get('DYNAMODB_TABLE', 'microservices-main-table')
        s3_bucket = os.environ.get('S3_BUCKET', 'microservices-data-bucket')
        sns_topic_arn = os.environ.get('SNS_TOPIC_ARN', '')
        sqs_queue_url = os.environ.get('SQS_QUEUE_URL', '')
        
        timestamp = datetime.utcnow().isoformat()
        
        event_data = {
            'function_name': function_name,
            'request_id': request_id,
            'timestamp': timestamp,
            'event': event
        }
        
        table = dynamodb.Table(table_name)
        table.put_item(Item={
            'id': request_id,
            'function_name': function_name,
            'timestamp': timestamp,
            'event_data': json.dumps(event, cls=DecimalEncoder),
            'status': 'processed'
        })
        
        s3_key = f"events/{function_name}/{request_id}.json"
        s3_client.put_object(
            Bucket=s3_bucket,
            Key=s3_key,
            Body=json.dumps(event_data, cls=DecimalEncoder),
            ContentType='application/json'
        )
        
        if sns_topic_arn:
            sns_client.publish(
                TopicArn=sns_topic_arn,
                Message=json.dumps(event_data, cls=DecimalEncoder),
                Subject=f'Event from {function_name}'
            )
        
        if sqs_queue_url:
            sqs_client.send_message(
                QueueUrl=sqs_queue_url,
                MessageBody=json.dumps(event_data, cls=DecimalEncoder),
                MessageAttributes={
                    'FunctionName': {
                        'StringValue': function_name,
                        'DataType': 'String'
                    },
                    'RequestId': {
                        'StringValue': request_id,
                        'DataType': 'String'
                    }
                }
            )
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'X-Request-Id': request_id
            },
            'body': json.dumps({
                'message': 'Successfully processed event',
                'request_id': request_id,
                'function_name': function_name,
                's3_location': f's3://{s3_bucket}/{s3_key}'
            })
        }
        
    except Exception as e:
        print(f"Error processing event: {str(e)}")
        
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'message': 'Error processing event',
                'error': str(e)
            })
        }


def process_s3_event(event, context):
    for record in event.get('Records', []):
        bucket = record['s3']['bucket']['name']
        key = record['s3']['object']['key']
        
        obj = s3_client.get_object(Bucket=bucket, Key=key)
        data = obj['Body'].read().decode('utf-8')
        
        print(f"Processing S3 object: {bucket}/{key}")
        
    return {'statusCode': 200, 'body': 'S3 event processed'}


def process_dynamodb_stream(event, context):
    for record in event.get('Records', []):
        event_name = record.get('eventName')
        
        if event_name in ['INSERT', 'MODIFY']:
            new_image = record['dynamodb'].get('NewImage', {})
            print(f"DynamoDB {event_name}: {new_image}")
        elif event_name == 'REMOVE':
            old_image = record['dynamodb'].get('OldImage', {})
            print(f"DynamoDB REMOVE: {old_image}")
    
    return {'statusCode': 200, 'body': 'DynamoDB stream processed'}


def process_sqs_event(event, context):
    for record in event.get('Records', []):
        message_body = record.get('body', '')
        message_attributes = record.get('messageAttributes', {})
        
        print(f"Processing SQS message: {message_body}")
        
        sqs_client.delete_message(
            QueueUrl=os.environ.get('SQS_QUEUE_URL'),
            ReceiptHandle=record['receiptHandle']
        )
    
    return {'statusCode': 200, 'body': 'SQS messages processed'}


def process_sns_event(event, context):
    for record in event.get('Records', []):
        message = record['Sns']['Message']
        subject = record['Sns'].get('Subject', 'No Subject')
        
        print(f"SNS Message - Subject: {subject}, Message: {message}")
    
    return {'statusCode': 200, 'body': 'SNS event processed'}